function toggleDarkMode(){document.documentElement.classList.toggle("dark"),document.head.removeChild(document.head.lastChild),localStorage.getItem("theme")?(localStorage.removeItem("theme"),applySyntaxTheme("light")):(localStorage.setItem("theme","dark"),applySyntaxTheme("dark")),console.log("Toggled Dark Mode")}function applySyntaxTheme(e){document.head.innerHTML=document.head.innerHTML+'<link id="css-'+e+'" rel="stylesheet" type="text/css" href="/css/syntax-'+e+'.css">'}localStorage.getItem("theme")?(document.documentElement.classList.toggle("dark"),applySyntaxTheme("dark")):applySyntaxTheme("light");